//import java.io.*;import java.util.Random;import java.net.*;/*automata is completely in first quadrant of the xy plane with its left bottim cellhaving (0, 0) coordinates and top right cell having (size-1, size-1) coordinatesno. of properties of the cells is initialized to 10 unless specified.*/ public class Automata {	public int AutomataSize;	double AccessibilityToEmployment[];	double AccessibilityToResidence[];	//landuse is trip generation and landuse2 is trip attraction	public URL url;	double oldAccessibilityToEmployment[];	double oldAccessibilityToResidence[];	public Automata() {		this.AutomataSize = -1;	}			/*		Similar to the nextInt(int n) available in java2. Since this function is not working in my comp		a similar implementation is adopted here		do {					bits = r.nextInt();					val = bits%pop;				} while (bits - val + (pop-1) < 0);  	*/		public void automata(URL url,int gridsize,DirectedGraph dg) {		Random r = new Random();		int bits, val;		this.url =url;		int vertices=dg.Vertices() ;		this.AutomataSize = dg.getDimension() ;				AccessibilityToEmployment=new double[AutomataSize*AutomataSize];		AccessibilityToResidence=new double[AutomataSize*AutomataSize];		oldAccessibilityToEmployment=new double[AutomataSize*AutomataSize];		oldAccessibilityToResidence=new double[AutomataSize*AutomataSize];						for (int i=0;i<AutomataSize;i++){			AccessibilityToEmployment[i]=0;			AccessibilityToResidence[i]=0;		}	}											/////////////////////////Print to screen functions	//////////////////// end of functions that print automata variables to screen		////////////////////  Fucntions that return the automata variables	public int   size() {		return AutomataSize;	}				public void updateLanduse(DirectedGraph dg, DijkstrasAlgo dalgo,int modeloption, boolean symm){	//update Accessibility;				double beta1,beta2;		beta1=beta2=0.03*60;		double cost=0;		for (int i=0;i<AutomataSize*AutomataSize;i++){			AccessibilityToEmployment[i]=0;			AccessibilityToResidence[i]=0;			for(int j=0;j<AutomataSize*AutomataSize;j++){				cost=dalgo.pLabel ( i+1,j+1, dg);					AccessibilityToEmployment[i]+=dg.TAZ_info [j][2]*Math.exp(-beta2*cost);					AccessibilityToResidence[i]+=dg.TAZ_info [j][1]*Math.exp(-beta1*cost);			}		}										//update land use			if (modeloption==0){		}		else if (modeloption==1){			//Revised Krugman Model				System.out.print("Revised Krugman Model running...\n");				double total_J=0,total_W=0;				double Pj[]=new double [AutomataSize*AutomataSize];				double Pw[]=new double [AutomataSize*AutomataSize];				for (int i=0;i<AutomataSize*AutomataSize;i++){					Pj[i]=Pw[i]=0;				}					double Pjbar=0,Pwbar=0;				double alpha=1.0;				double gamma=0.048*60;								for (int i=0;i<AutomataSize*AutomataSize;i++){					for (int j=0;j<AutomataSize*AutomataSize;j++){													Pj[i]+=(dg.TAZ_info[j][2]*Math.exp(-gamma*dalgo.pLabel( i+1,j+1, dg))+dg.TAZ_info[j][1]*Math.exp(-gamma*dalgo.pLabel( i+1,j+1, dg)));							Pw[i]+=(dg.TAZ_info[j][2]*Math.exp(-gamma*dalgo.pLabel( i+1,j+1, dg))-alpha*dg.TAZ_info[j][1]*Math.exp(-gamma*dalgo.pLabel( i+1,j+1, dg)));															}										//System.out.print(Pj[i]+"\t");										total_J+=dg.TAZ_info[i][2];					total_W+=dg.TAZ_info[i][1];					Pjbar+=Pj[i]*dg.TAZ_info[i][2];					Pwbar+=Pw[i]*dg.TAZ_info[i][1];				}								System.out.print("\n");						Pjbar=Pjbar/total_J;				Pwbar=Pwbar/total_W;				for (int i=0;i<AutomataSize*AutomataSize;i++){					dg.TAZ_info[i][2]=dg.TAZ_info[i][2]+(float)(0.000001*(Pj[i]-Pjbar))*dg.TAZ_info[i][2];					dg.TAZ_info[i][1]=dg.TAZ_info[i][1]+(float)(0.000001*(Pw[i]-Pwbar))*dg.TAZ_info[i][1];					//System.out.print(dg.TAZ_info[i][1]+"\t"+dg.TAZ_info[i][1]+"\n");				}			}		else if (modeloption==2){			System.out.print("Revised Krugman Model ii running...\n");			double total_J=0,total_W=0,tJ=0,tW=0;			double Pj[]=new double [AutomataSize*AutomataSize];			double Pw[]=new double [AutomataSize*AutomataSize];			for (int i=0;i<AutomataSize*AutomataSize;i++){				Pj[i]=Pw[i]=0;			}				double Pjbar=0,Pwbar=0;			double alpha=1.0;			double gamma=0.048*60;			double coeff=0.0003;				for (int i=0;i<AutomataSize*AutomataSize;i++){				for (int j=0;j<AutomataSize*AutomataSize;j++){											Pj[i]+=(dg.TAZ_info[j][2]*Math.exp(-gamma*dalgo.pLabel( i+1,j+1, dg))+dg.TAZ_info[j][1]*Math.exp(-gamma*dalgo.pLabel( i+1,j+1, dg)));						Pw[i]+=(dg.TAZ_info[j][2]*Math.exp(-gamma*dalgo.pLabel( i+1,j+1, dg))-alpha*dg.TAZ_info[j][1]*Math.exp(-gamma*dalgo.pLabel( i+1,j+1, dg)));												}								//System.out.print(Pj[i]+"\t");								total_J+=dg.TAZ_info[i][2];				total_W+=dg.TAZ_info[i][1];				Pjbar+=Pj[i]*dg.TAZ_info[i][2];				Pwbar+=Pw[i]*dg.TAZ_info[i][1];			}						System.out.print("\n");						Pjbar=Pjbar/total_J;			Pwbar=Pwbar/total_W;			for (int i=0;i<AutomataSize*AutomataSize;i++){				dg.TAZ_info[i][2]=dg.TAZ_info[i][2]+(float)(coeff*(Pj[i]-Pjbar))*dg.TAZ_info[i][2];				dg.TAZ_info[i][1]=dg.TAZ_info[i][1]+(float)(coeff*(Pw[i]-Pwbar))*dg.TAZ_info[i][1];				if(dg.TAZ_info[i][1]<5)dg.TAZ_info[i][1]=5;				tW+=dg.TAZ_info[i][1];				if(dg.TAZ_info[i][2]<5)dg.TAZ_info[i][2]=5;				tJ+=dg.TAZ_info[i][2];			}				for (int i=0;i<AutomataSize*AutomataSize;i++){				dg.TAZ_info[i][2]*=total_J/tJ;				dg.TAZ_info[i][1]*=total_W/tW;			}		}				else if (modeloption==3){				for (int i=0;i<AutomataSize*AutomataSize;i++){					dg.TAZ_info[i][2]=1000;				}				System.out.print("Krugman Model running...\n");								double total_W=0;				double P[]=new double [AutomataSize*AutomataSize];								for (int i=0;i<AutomataSize*AutomataSize;i++){					P[i]=0;				}					double Pbar=0;				double gamma1=0.2*60,gamma2=0.25*60;										for (int i=0;i<AutomataSize*AutomataSize;i++){					for (int j=0;j<AutomataSize*AutomataSize;j++){																				P[i]+=(dg.TAZ_info[j][2]*Math.exp(-gamma1*dalgo.pLabel( i+1,j+1, dg))-dg.TAZ_info[j][1]*Math.exp(-gamma2*dalgo.pLabel( i+1,j+1, dg)));																}					total_W+=dg.TAZ_info[i][1];										Pbar+=P[i]*dg.TAZ_info[i][1];									}							Pbar=Pbar/total_W;								for (int i=0;i<AutomataSize*AutomataSize;i++){					dg.TAZ_info[i][1]=dg.TAZ_info[i][1]+(float)(0.000001*(P[i]-Pbar))*dg.TAZ_info[i][1];				}			}				else if (modeloption==4){			//LXZ Model				System.out.print("LXZ Model running...\n");				double totalJ=0,totalW=0;				double averageE;				double denominatorJ=0, denominatorW=0;						double coeff1=0.5,coeff2=0.5,coeff3=0.5,coeff4=-0.5;						//Calculate the denominators						for (int i=0;i<AutomataSize*AutomataSize;i++){					totalW+=dg.TAZ_info[i][1];					totalJ+=dg.TAZ_info[i][2];					denominatorJ+=Math.pow(AccessibilityToEmployment[i],coeff1)*Math.pow(AccessibilityToResidence[i],coeff2);					denominatorW+=Math.pow(AccessibilityToEmployment[i],coeff3)*Math.pow(AccessibilityToResidence[i],coeff4);				}						for (int i=0;i<AutomataSize*AutomataSize;i++){					//dg.TAZ_info[i][1] =(float)(totalW*Math.pow(AccessibilityToEmployment[i],coeff3)*Math.pow(AccessibilityToResidence[i],coeff4)/denominatorW);					//dg.TAZ_info[i][2] =(float)(totalJ*Math.pow(AccessibilityToEmployment[i],coeff1)*Math.pow(AccessibilityToResidence[i],coeff2)/denominatorJ);										//dg.TAZ_info[i][1] +=(float)*(Math.pow(AccessibilityToEmployment[i],coeff3)*Math.pow(AccessibilityToResidence[i],coeff4)/denominatorW-1/(automatasize*automatasize));					//dg.TAZ_info[i][2] +=(float)(totalJ*Math.pow(AccessibilityToEmployment[i],coeff1)*Math.pow(AccessibilityToResidence[i],coeff2)/denominatorJ);				}		}			else if (modeloption==5){			System.out.print("LUCI Model running...\n");		//LUCI Model			double b=-0.08;			double totalP,totalE;			double averageE;			double denominatorP, denominatorE;			totalP=0;			totalE=0;			averageE = 0;			denominatorP = 0;			denominatorE =  0;			//Calculate the average Employment			for (int i=0;i<AutomataSize*AutomataSize;i++){				totalP+=dg.TAZ_info[i][1];				totalE+=dg.TAZ_info[i][2];			}			averageE=totalE/(AutomataSize*AutomataSize);					for (int i=0;i<AutomataSize*AutomataSize;i++){				denominatorP+=dg.TAZ_info[i][1]*Math.exp(b/averageE*(AccessibilityToEmployment[i]-oldAccessibilityToEmployment[i]));				denominatorE+=dg.TAZ_info[i][2]*Math.exp(Math.pow((AccessibilityToResidence[i]/oldAccessibilityToResidence[i]),b));			}					for (int i=0;i<AutomataSize*AutomataSize;i++){				dg.TAZ_info[i][1] =(float)(totalP*dg.TAZ_info[i][1]*Math.exp(b/averageE*(AccessibilityToEmployment[i]-oldAccessibilityToEmployment[i]))/denominatorP);				dg.TAZ_info[i][2] =(float)(totalE*dg.TAZ_info[i][2]*Math.exp(Math.pow((AccessibilityToResidence[i]/oldAccessibilityToResidence[i]),b))/denominatorE);				oldAccessibilityToEmployment[i] = AccessibilityToEmployment[i];				oldAccessibilityToResidence[i] = AccessibilityToResidence[i];			}		}				else if (modeloption==6){			System.out.print("Incorporating moving cost...\n");			double fixedMovingReduction=0.2,varMovingReduction=0.02, movingReductionRate=0.0;						double Pj[]=new double [AutomataSize*AutomataSize];			double Pw[]=new double [AutomataSize*AutomataSize];			for (int i=0;i<AutomataSize*AutomataSize;i++){				Pj[i]=Pw[i]=0;			}							//Reduced potential of B if moving from A to B			double ReducedPj[][]=new double[AutomataSize*AutomataSize][AutomataSize*AutomataSize];			double ReducedPw[][]=new double[AutomataSize*AutomataSize][AutomataSize*AutomataSize];			double denominatorJ[]=new double[AutomataSize*AutomataSize];			double denominatorW[]=new double[AutomataSize*AutomataSize];			double oldTazJobs[]=new double[AutomataSize*AutomataSize];			double oldTazWorkers[]=new double[AutomataSize*AutomataSize];						double alpha=0.9;			double gamma=0.1*60;			double eta=0.8;						double coeff1,coeff2,coeff3,coeff4;			coeff1=coeff2=coeff3=1.0;			coeff4=-coeff1;			/*			//Calculate the denominators				for (int i=0;i<AutomataSize*AutomataSize;i++){				totalW+=dg.TAZ_info[i][1];				totalJ+=dg.TAZ_info[i][2];				denominatorJ+=Math.pow(AccessibilityToEmployment[i],coeff1)*Math.pow(AccessibilityToResidence[i],coeff2);				denominatorW+=Math.pow(AccessibilityToEmployment[i],coeff3)*Math.pow(AccessibilityToResidence[i],coeff4);			}				for (int i=0;i<AutomataSize*AutomataSize;i++){				//dg.TAZ_info[i][1] =(float)(totalW*Math.pow(AccessibilityToEmployment[i],coeff3)*Math.pow(AccessibilityToResidence[i],coeff4)/denominatorW);				//dg.TAZ_info[i][2] =(float)(totalJ*Math.pow(AccessibilityToEmployment[i],coeff1)*Math.pow(AccessibilityToResidence[i],coeff2)/denominatorJ);								//dg.TAZ_info[i][1] +=(float)*(Math.pow(AccessibilityToEmployment[i],coeff3)*Math.pow(AccessibilityToResidence[i],coeff4)/denominatorW-1/(automatasize*automatasize));				//dg.TAZ_info[i][2] +=(float)(totalJ*Math.pow(AccessibilityToEmployment[i],coeff1)*Math.pow(AccessibilityToResidence[i],coeff2)/denominatorJ);			}			*/						for (int i=0;i<AutomataSize*AutomataSize;i++){					Pj[i]=Math.pow(AccessibilityToEmployment[i],coeff1)*Math.pow(AccessibilityToResidence[i],coeff2);					Pw[i]=Math.pow(AccessibilityToEmployment[i],coeff3)*Math.pow(AccessibilityToResidence[i],coeff4);														}			//			for (int i=0;i<AutomataSize*AutomataSize;i++){//				for (int j=0;j<AutomataSize*AutomataSize;j++){//					//						Pj[i]+=(dg.TAZ_info[j][2]*Math.exp(-gamma*dalgo.pLabel( i+1,j+1, dg))+dg.TAZ_info[j][1]*Math.exp(-gamma*dalgo.pLabel( i+1,j+1, dg)));//						Pw[i]+=(dg.TAZ_info[j][2]*Math.exp(-gamma*dalgo.pLabel( i+1,j+1, dg))-alpha*dg.TAZ_info[j][1]*Math.exp(-gamma*dalgo.pLabel( i+1,j+1, dg)));//				}				//			}						for (int i=0;i<AutomataSize*AutomataSize;i++){				oldTazJobs[i]=dg.TAZ_info[i][2];				oldTazWorkers[i]=dg.TAZ_info[i][1];				dg.TAZ_info[i][1]=dg.TAZ_info[i][2]=0;			}			for (int i=0;i<AutomataSize*AutomataSize;i++){				denominatorJ[i]=0;				denominatorW[i]=0;				for (int j=0;j<AutomataSize*AutomataSize;j++){					double distance;					if(i==j){						movingReductionRate=1.0;					}					else{						distance=0.2*Math.sqrt(Math.pow(dg.XCoordinate(i+1)-dg.XCoordinate(j+1), 2)+Math.pow(dg.YCoordinate(i+1)-dg.YCoordinate(j+1), 2));						movingReductionRate=1-fixedMovingReduction-varMovingReduction*distance;						//if(movingReductionRate<0.05)movingReductionRate=0.05;					}										//movingReductionRate=1.0;										ReducedPj[i][j]=Pj[j]*movingReductionRate;					ReducedPw[i][j]=Pw[j]*movingReductionRate;							//denominatorJ[i]+=ReducedPj[i][j];					//denominatorW[i]+=ReducedPw[i][j];					denominatorJ[i]+=Math.pow(ReducedPj[i][j],eta);					denominatorW[i]+=Math.pow(ReducedPw[i][j],eta);					//if(Pj[i]<=ReducedPj[i][j])denominatorJ[i]+=Math.exp(eta*(ReducedPj[i][j]-Pj[i]));					//if(Pw[i]<=ReducedPw[i][j])denominatorW[i]+=Math.exp((eta*ReducedPw[i][j]-Pw[i]));													}							}			for (int i=0;i<AutomataSize*AutomataSize;i++){				for (int j=0;j<AutomataSize*AutomataSize;j++){					//if(Pw[i]<=ReducedPw[i][j])dg.TAZ_info[j][1]+=oldTazWorkers[i]*Math.exp(eta*(ReducedPw[i][j]-Pw[i]))/denominatorW[i];					//if(Pj[i]<=ReducedPj[i][j])dg.TAZ_info[j][2]+=oldTazJobs[i]*Math.exp(eta*(ReducedPj[i][j]-Pj[i]))/denominatorJ[i];					dg.TAZ_info[j][1]+=oldTazWorkers[i]*Math.pow(ReducedPw[i][j],eta)/denominatorW[i];					dg.TAZ_info[j][2]+=oldTazJobs[i]*Math.pow(ReducedPj[i][j],eta)/denominatorJ[i];				}							}			for (int i=0;i<AutomataSize*AutomataSize;i++){				System.out.print(dg.TAZ_info[i][1]+"\t"+dg.TAZ_info[i][2]+"\n");			}					if(symm)symmetricLanduse(dg);		}				else if (modeloption==7){			System.out.print("Incorporating moving cost ii...\n");			//double fixedMovingReduction=0.2,varMovingReduction=0.02, movingReductionRate=0.0;						double Pj[]=new double [AutomataSize*AutomataSize];			double Pw[]=new double [AutomataSize*AutomataSize];			for (int i=0;i<AutomataSize*AutomataSize;i++){				Pj[i]=Pw[i]=0;			}							//Reduced potential of B if moving from A to B			double ReducedPj[][]=new double[AutomataSize*AutomataSize][AutomataSize*AutomataSize];			double ReducedPw[][]=new double[AutomataSize*AutomataSize][AutomataSize*AutomataSize];			double denominatorJ[]=new double[AutomataSize*AutomataSize];			double denominatorW[]=new double[AutomataSize*AutomataSize];			double oldTazJobs[]=new double[AutomataSize*AutomataSize];			double oldTazWorkers[]=new double[AutomataSize*AutomataSize];						double eta=0.8;						double coeff1,coeff2,coeff3,coeff4;			coeff1=coeff2=1.0;			coeff3=0.9;			coeff4=-0.9;			/*			//Calculate the denominators				for (int i=0;i<AutomataSize*AutomataSize;i++){				totalW+=dg.TAZ_info[i][1];				totalJ+=dg.TAZ_info[i][2];				denominatorJ+=Math.pow(AccessibilityToEmployment[i],coeff1)*Math.pow(AccessibilityToResidence[i],coeff2);				denominatorW+=Math.pow(AccessibilityToEmployment[i],coeff3)*Math.pow(AccessibilityToResidence[i],coeff4);			}				for (int i=0;i<AutomataSize*AutomataSize;i++){				//dg.TAZ_info[i][1] =(float)(totalW*Math.pow(AccessibilityToEmployment[i],coeff3)*Math.pow(AccessibilityToResidence[i],coeff4)/denominatorW);				//dg.TAZ_info[i][2] =(float)(totalJ*Math.pow(AccessibilityToEmployment[i],coeff1)*Math.pow(AccessibilityToResidence[i],coeff2)/denominatorJ);								//dg.TAZ_info[i][1] +=(float)*(Math.pow(AccessibilityToEmployment[i],coeff3)*Math.pow(AccessibilityToResidence[i],coeff4)/denominatorW-1/(automatasize*automatasize));				//dg.TAZ_info[i][2] +=(float)(totalJ*Math.pow(AccessibilityToEmployment[i],coeff1)*Math.pow(AccessibilityToResidence[i],coeff2)/denominatorJ);			}			*/						for (int i=0;i<AutomataSize*AutomataSize;i++){					Pj[i]=Math.pow(AccessibilityToEmployment[i],coeff1)*Math.pow(AccessibilityToResidence[i],coeff2);					Pw[i]=Math.pow(AccessibilityToEmployment[i],coeff3)*Math.pow(AccessibilityToResidence[i],coeff4);														}									for (int i=0;i<AutomataSize*AutomataSize;i++){				oldTazJobs[i]=dg.TAZ_info[i][2];				oldTazWorkers[i]=dg.TAZ_info[i][1];				dg.TAZ_info[i][1]=dg.TAZ_info[i][2]=0;			}			for (int i=0;i<AutomataSize*AutomataSize;i++){				denominatorJ[i]=0;				denominatorW[i]=0;				for (int j=0;j<AutomataSize*AutomataSize;j++){					double distance;					if(i==j){						ReducedPj[i][j]=Pj[j];						ReducedPw[i][j]=Pw[j];					}					else{						ReducedPj[i][j]=Math.pow(Pj[j], eta);						ReducedPw[i][j]=Math.pow(Pw[j], eta);					}										denominatorJ[i]+=ReducedPj[i][j];					denominatorW[i]+=ReducedPw[i][j];								}							}			for (int i=0;i<AutomataSize*AutomataSize;i++){				for (int j=0;j<AutomataSize*AutomataSize;j++){					//if(Pw[i]<=ReducedPw[i][j])dg.TAZ_info[j][1]+=oldTazWorkers[i]*Math.exp(eta*(ReducedPw[i][j]-Pw[i]))/denominatorW[i];					//if(Pj[i]<=ReducedPj[i][j])dg.TAZ_info[j][2]+=oldTazJobs[i]*Math.exp(eta*(ReducedPj[i][j]-Pj[i]))/denominatorJ[i];					dg.TAZ_info[j][1]+=oldTazWorkers[i]*ReducedPw[i][j]/denominatorW[i];					dg.TAZ_info[j][2]+=oldTazJobs[i]*ReducedPj[i][j]/denominatorJ[i];				}							}			//			float total_J=0,tJ=0,total_W=0,tW=0;//			for (int i=0;i<AutomataSize*AutomataSize;i++){//				float max=5000;//				total_J+=dg.TAZ_info[i][2];//				total_W+=dg.TAZ_info[i][1];//				if(dg.TAZ_info[i][2]>max)dg.TAZ_info[i][2]=max;//				if(dg.TAZ_info[i][1]>max)dg.TAZ_info[i][1]=max;//				tJ+=dg.TAZ_info[i][2];//				tW+=dg.TAZ_info[i][1];////			}//			//			for (int i=0;i<AutomataSize*AutomataSize;i++){//				dg.TAZ_info[i][2]*=total_J/tJ;//				dg.TAZ_info[i][1]*=total_W/tW;//			}			for (int i=0;i<AutomataSize*AutomataSize;i++){				System.out.print(dg.TAZ_info[i][1]+"\t"+dg.TAZ_info[i][2]+"\n");			}					if(symm)symmetricLanduse(dg);		}		}		private void symmetricLanduse (DirectedGraph dgraph){		Dimension zones[] = new Dimension[8];		float symmZoneJobs[]=new float[dgraph.Vertices()];		float symmZoneWorkers[]=new float[dgraph.Vertices()];						for(int k=0; k<8; k++) {			zones[k] = new Dimension();		}				for (int i=0;i<dgraph.Vertices();i++){			int zone=i+1;			if(true){				float sum_jobs=0,sum_workers=0;				zones[0].setSize( node(zone,dgraph) );								zones[1].setSize( imageV_Axis( zones[0],dgraph )  );								zones[2].setSize( imageH_Axis( zones[1],dgraph )  );								zones[3].setSize( imageV_Axis( zones[2],dgraph )   );								zones[4].setSize( diagonalImage( zones[0],dgraph )  );								zones[5].setSize( imageV_Axis( zones[4] ,dgraph )  );								zones[6].setSize( imageH_Axis( zones[5],dgraph )   );								zones[7].setSize( imageV_Axis( zones[6] ,dgraph )  );								for(int k =0; k<8 ; k++) {					//System.out.print("k="+k+"\n");					int zoneid = nodenum( zones[k],dgraph );					//System.out.print("k:"+k+"\tfirst--"+firstNN+"\tsecond--"+secondNN+"\n");										sum_jobs+= dgraph.TAZ_info[zoneid-1][2];					sum_workers+=dgraph.TAZ_info[zoneid-1][1];				}								symmZoneJobs[i]=sum_jobs/8;				symmZoneWorkers[i]=sum_workers/8;			}		}				for (int p=0;p<dgraph.Vertices();p++){			dgraph.TAZ_info[p][2]=symmZoneJobs[p];			dgraph.TAZ_info[p][1]=symmZoneWorkers[p];		}	}	//dimension int width,int height	public int nodenum( Dimension d,DirectedGraph dgraph) {		int temp=-1;				for(int i=0;i<dgraph.Vertices();i++){				if(Math.round(1000*(dgraph.XCoordinate( i+1)-d.width))==0.0 && Math.round(1000*(dgraph.YCoordinate( i+1)-d.height ))==0.0)					temp=i+1; 						}		if(temp<1)System.out.print("error!\t"+d.width +"\t"+d.height+"\n" );			return temp;			}		public Dimension node(int nodeNumber,DirectedGraph dgraph) {		return new Dimension(dgraph.XCoordinate(nodeNumber),dgraph.YCoordinate(nodeNumber));			}		public Dimension imageV_Axis( Dimension d,DirectedGraph dgraph) {		return new Dimension( d.width, dgraph.XCoordinate(dgraph.getDimension()*dgraph.getDimension() )+dgraph.XCoordinate( 1)-d.height);	}		public Dimension imageH_Axis( Dimension d,DirectedGraph dgraph) {		return new Dimension( dgraph.YCoordinate(dgraph.getDimension()*dgraph.getDimension() )+dgraph.YCoordinate( 1)-d.width, d.height);	}		public Dimension diagonalImage( Dimension d,DirectedGraph dgraph) {		return new Dimension( d.height, d.width);	}	class Dimension{		double width;		double height;		Dimension(){;		}		Dimension(double w,double h){			width=w;			height=h;		}		Dimension setSize(Dimension n){			width=n.width ;			height=n.height ;			return n;		}	}		public void initialAccessibility(DirectedGraph dg, DijkstrasAlgo dalgo){		double beta1=0.1, beta2=0.1;		double cost=0;		for (int i=0;i<AutomataSize*AutomataSize;i++){			oldAccessibilityToEmployment[i]=0;			oldAccessibilityToResidence[i]=0;			for(int j=0;j<AutomataSize*AutomataSize;j++){				cost=dalgo.pLabel( i+1,j+1, dg);				if(cost!=-1 && i!=j){									oldAccessibilityToEmployment[i]+=dg.TAZ_info [j][2]*Math.exp(-beta2*cost);					oldAccessibilityToResidence[i]+=dg.TAZ_info [j][1]*Math.exp(-beta1*cost);				}			}		}	}}